mapper.select:
SELECT schema_name, digest, max(digest_text) AS digest_text, sum(delta_count) AS exec_count, sum(delta_timer_wait) AS total_timer_wait, CASE WHEN sum(delta_count) > 0 THEN sum(delta_timer_wait) / 1000000 / sum(delta_count) ELSE 0 END AS avg_timer_wait_us, max(avg_timer_wait_us) AS max_avg_timer_wait_us, sum(delta_rows_examined) AS rows_examined, sum(delta_rows_sent) AS rows_sent, sum(delta_lock_time) AS lock_time, sum(delta_sort_rows) AS sort_rows, sum(delta_no_index_used) AS no_index_used, sum(delta_tmp_tables) AS tmp_tables, sum(delta_tmp_disk_tables) AS tmp_disk_tables, min(collect_time) AS first_seen, max(collect_time) AS last_seen FROM metric_top_sql WHERE instance_id = #{instanceId} AND collect_time >= #{from} AND collect_time <= #{to}
AND digest_text ILIKE '%' || #{keyword} || '%'
AND schema_name = #{schemaName}
AND upper(digest_text) LIKE #{sqlTypePrefix}
GROUP BY schema_name, digest
HAVING 1 = 1
AND CASE WHEN sum(delta_count) > 0 THEN sum(delta_timer_wait) / 1000000 / sum(delta_count) ELSE 0 END >= #{minAvgUs}
AND CASE WHEN sum(delta_count) > 0 THEN sum(delta_timer_wait) / 1000000 / sum(delta_count) ELSE 0 END <= #{maxAvgUs}
ORDER BY ${orderBy} LIMIT #{limit} OFFSET #{offset}

SELECT count(*) FROM (
SELECT 1
FROM metric_top_sql
WHERE instance_id = #{instanceId}
  AND collect_time >= #{from} AND collect_time <= #{to}

    AND digest_text ILIKE '%' || #{keyword} || '%'


    AND schema_name = #{schemaName}


    AND upper(digest_text) LIKE #{sqlTypePrefix}

GROUP BY schema_name, digest

  HAVING 1 = 1

    AND CASE WHEN sum(delta_count) > 0
        THEN sum(delta_timer_wait) / 1000000 / sum(delta_count) ELSE 0 END >= #{minAvgUs}


    AND CASE WHEN sum(delta_count) > 0
        THEN sum(delta_timer_wait) / 1000000 / sum(delta_count) ELSE 0 END <= #{maxAvgUs}


) t

SELECT collect_time, schema_name, digest, digest_text,
  delta_count, avg_timer_wait_us, delta_timer_wait,
  delta_rows_examined, delta_rows_sent,
  delta_lock_time, delta_sort_rows, delta_no_index_used,
  delta_tmp_tables, delta_tmp_disk_tables
FROM metric_top_sql
WHERE instance_id = #{instanceId}
  AND collect_time >= #{from} AND collect_time <= #{to}

    AND upper(digest_text) LIKE #{sqlTypePrefix}


    AND avg_timer_wait_us >= #{minAvgUs}


    AND avg_timer_wait_us <= #{maxAvgUs}


    AND digest = #{digest}
    AND schema_name IS NOT DISTINCT FROM #{targetSchema,jdbcType=VARCHAR}

ORDER BY collect_time DESC, avg_timer_wait_us DESC
LIMIT #{limit} OFFSET #{offset}

SELECT count(*) FROM metric_top_sql
WHERE instance_id = #{instanceId}
  AND collect_time >= #{from} AND collect_time <= #{to}

    AND upper(digest_text) LIKE #{sqlTypePrefix}


    AND avg_timer_wait_us >= #{minAvgUs}


    AND avg_timer_wait_us <= #{maxAvgUs}


    AND digest = #{digest}
    AND schema_name IS NOT DISTINCT FROM #{targetSchema,jdbcType=VARCHAR}

SELECT collect_time, delta_count, avg_timer_wait_us, delta_rows_examined
FROM metric_top_sql
WHERE instance_id = #{instanceId}
  AND digest = #{digest}
  AND schema_name IS NOT DISTINCT FROM #{schemaName,jdbcType=VARCHAR}
  AND collect_time >= #{from} AND collect_time <= #{to}
ORDER BY collect_time ASC
LIMIT 2000
